function IdentityReel(){const [frame,setFrame]=useState(0);useEffect(()=>{const timer=setInterval(()=>setFrame(f=>(f+1)%identityFrames.length),7000);return()=>clearInterval(timer)},[]);const f=identityFrames[frame];return <section className="identity-reel panel"><div className="identity-photo" key={f.src}><img src={f.src} alt="Tolu personal archive"/><div className="scanline"/></div><div className="identity-copy"><span className="eyebrow">PERSONAL ARCHIVE // AUTO ROTATION</span><small>{f.era}</small><h2>{f.title}</h2><p>{f.text}</p><div className="reel-dots">{identityFrames.map((x,i)=><button aria-label={`Show ${x.title}`} className={i===frame?"active":""} onClick={()=>setFrame(i)} key={x.src}/>)}</div></div><div className="identity-code"><span>MEMORY</span><strong>{String(frame+1).padStart(2,"0")}</strong><small>/ {String(identityFrames.length).padStart(2,"0")}</small></div></section>}

