function WhatsAppSignalMap({chats}:{chats:WhatsAppChat[]}){const total=chats.reduce((n,c)=>n+c.messages,0);return <section className="whatsapp-map panel"><header><div><span className="eyebrow">WHATSAPP INTELLIGENCE // RELEVANCE WITHOUT CLUTTER</span><h2>{total.toLocaleString()} messages reduced to useful context.</h2><p>A chat is not automatically a task. The system connects evidence to an existing situation unless there is a concrete Tolu action, commitment, deadline or risk.</p></div><div className="wa-total"><strong>{chats.length}</strong><span>INDEXED CHATS</span></div></header><div className="wa-grid">{chats.map(c=><article key={c.id}><div className="wa-orb"><span>{c.id}</span><strong>{c.messages}</strong><small>MESSAGES</small></div><div><span className="tag">{c.type}</span><h3>{c.name}</h3><p>{c.summary}</p><small>{c.scopeRule}</small><div className="wa-links">{c.taskIds.map(id=><b key={id}>{id}</b>)}{c.sourceUrl&&<a href={c.sourceUrl} target="_blank" rel="noreferrer">Open export <ExternalLink/></a>}</div></div></article>)}</div><div className="wa-logic"><GitBranch/><p><b>CONNECTION LOGIC</b>Message → identify whose issue it is → remove social chatter → match a live task by people, topic and date → add a timeline event → create a task only when Tolu has a real next action.</p></div></section>}

