function Intel({useful,imports,whatsApp,syncedAt}:{useful:UsefulEmail[];imports:ImportRecord[];whatsApp:WhatsAppChat[];syncedAt?:string}){const [filter,setFilter]=useState("All");const categories=["All",...new Set(useful.map(x=>x.category))];const shown=useful.filter(x=>filter==="All"||x.category===filter);const sourceTypes=[...new Set(imports.map(x=>x.sourceType))];return <div className="page intel-page"><PageHead eyebrow="SIGNAL DECK // USEFUL EMAILS & SOURCE INGESTION" title="Not every email is a task. Some are leverage." text="The live sheet now separates useful evidence, relevant opportunities and genuine benefits from urgent command-centre missions."/><section className="intel-status panel"><div><Radio/><span>APP SNAPSHOT</span><strong>{syncedAt?new Date(syncedAt).toLocaleString("en-GB",{dateStyle:"medium",timeStyle:"short"}):"Bundled baseline"}</strong></div><div><Database/><span>USEFUL SIGNALS</span><strong>{useful.length}</strong></div><div><Upload/><span>PROCESSED IMPORTS</span><strong>{imports.length||"SYNC TO LOAD"}</strong></div><div><ShieldCheck/><span>SOURCE TYPES</span><strong>{sourceTypes.length?sourceTypes.join(" + "):"XLSX REQUIRED"}</strong></div></section><div className="filters intel-filters">{categories.map(c=><button className={filter===c?"active":""} onClick={()=>setFilter(c)} key={c}>{c}</button>)}</div><div className="intel-grid">{shown.map((e,i)=><article className="intel-card panel" key={`${e.subject}-${i}`}><header><span className={`tag ${e.relevance.toLowerCase()}`}>{e.relevance} // {e.category}</span><small>{e.date}</small></header><span className="intel-sender">{e.sender}</span><h2>{e.subject}</h2><p>{e.summary}</p><div className="intel-value"><span>VALUE / PAY / BENEFIT</span><strong>{e.value||"Evidence or opportunity"}</strong></div>{e.deadline&&<div className="intel-deadline"><Clock3/> {e.deadline}</div>}<div className="intel-action"><Sparkles/><p><b>RECOMMENDED</b>{e.action}</p></div><footer>{e.taskId&&<span>{e.taskId}</span>}<span>{e.status}</span>{e.sourceUrl&&<a href={gmailUrl(e.sourceUrl)} target="_blank" rel="noreferrer">Open exact email <ExternalLink/></a>}</footer></article>)}</div><WhatsAppSignalMap chats={whatsApp}/>{imports.length>0&&<section className="ingestion-ledger panel"><span className="eyebrow">INGESTION LEDGER // WHAT THE SHEET AUTOMATION HAS PROCESSED</span>{imports.slice().reverse().map(x=><article key={x.id}><div><strong>{x.sourceType}</strong><span>{x.processed}</span></div><div><b>{x.name}</b><p>{x.result}</p></div><span className="tag">{x.status}</span></article>)}</section>}</div>}

function Stat({n,label}:{n:number;label:string}){return <div className="stat"><strong>{n}</strong><span>{label}</span></div>}
function MissionCard({m,complete}:{m:Mission;complete:(s:string)=>void}){return <article className="support panel"><span className="tag critical">{m.priority}</span><h3>{m.title}</h3><p>{m.next}</p><footer><span><Clock3/> {m.days} day{m.days!==1?"s":""}</span>{m.sourceUrl&&<a href={gmailUrl(m.sourceUrl)} target="_blank" rel="noreferrer"><ExternalLink/> Source</a>}<button onClick={()=>complete(m.id)}><Check/></button></footer></article>}
function SoundDeck({music,setMusic}:{music:boolean;setMusic:(x:boolean)=>void}){return <section className="sound panel"><div className="section-title"><span><Headphones/> SOUND DECK</span><i className="live-dot"/></div><div className="album"><div className="album-art"><Music2/></div><div><small>FOCUS PROTOCOL</small><strong>Deep Work // Tolu Mix</strong><span>Spotify connection ready</span></div></div><div className="player"><button onClick={()=>setMusic(!music)}>{music?<Volume2/>:<Music2/>}</button><div className="track"><i style={{width:music?"42%":"8%"}}/></div><span>{music?"18:42":"00:00"}</span></div></section>}
function NextEvent({onOpen}:{onOpen:()=>void}){return <section className="mini panel"><span className="eyebrow">NEXT EVENT</span><div className="mini-row"><CalendarDays/><div><strong>Solicitor consultation</strong><span>Tomorrow // 14:00</span></div></div><button onClick={onOpen}>Open timeline <ChevronRight/></button></section>}
function Vitals({energy,mood,onCheck}:{energy:number;mood:number;onCheck:()=>void}){return <section className="mini panel"><span className="eyebrow">SYSTEM VITALS</span><div className="vitals"><div><HeartPulse/><b>{energy}/5</b><span>ENERGY</span></div><div><Activity/><b>{mood}/5</b><span>MOOD</span></div></div><button onClick={onCheck}>Daily check-in <ChevronRight/></button></section>}
function Momentum({done}:{done:number}){return <section className="mini momentum panel"><span className="eyebrow">MOMENTUM</span><div className="ring" style={{"--p":`${Math.max(8,done*10)}%`} as React.CSSProperties}><strong>{done}</strong><span>WINS</span></div><p>Returning counts. The next action counts more.</p></section>}
function Reduced({mission,complete}:{mission:Mission|undefined;complete:(s:string)=>void}){return <section className="reduced-card panel"><MoonStar/><span className="eyebrow">REDUCED POWER // NO SHAME, NO DRIFT</span><h2>Today only needs one honest win.</h2>{mission&&<><h3>{mission.title}</h3><p>{mission.next}</p><button className="primary" onClick={()=>complete(mission.id)}>Complete minimum win <Check/></button></>}<div className="care-row"><span>Drink water</span><span>Eat something</span><span>Message someone safe</span></div></section>}

function Missions({items,timeline,workLog,done,complete,saveProgress,openUpdates}:{items:Mission[];timeline:TimelineEntry[];workLog:TaskWorkEntry[];done:string[];complete:(s:string)=>void;saveProgress:(mission:Mission,planSteps:string[],checked:string[],workNote:string,nextWorkSession:string)=>void;openUpdates:()=>void}) {
  const [filter,setFilter]=useState("All");
  const [selected,setSelected]=useState<Mission>();
  const [hideClosed,setHideClosed]=useStored("tolu-hide-closed-tasks",true);
  const filters=["All","Open","Critical","High","Waiting","Closed"];
  const closedStatuses=["completed","complete","closed","resolved","archived","cancelled","canceled"];
  const isClosed=(m:Mission)=>{
    const status=(m.status||"").trim().toLowerCase();
    return done.includes(m.id)||closedStatuses.some(value=>status===value||status.startsWith(value+" "));
  };
  const isWaiting=(m:Mission)=>{
    const status=(m.status||"").trim().toLowerCase();
    const waiting=(m.waiting||"").trim().toLowerCase();
    const waitingOnSomeone=Boolean(waiting&&!["tolu","none","n/a","na","-"].includes(waiting));
    return !isClosed(m)&&(/waiting|pending|on hold|blocked/.test(status)||waitingOnSomeone);
  };
  const matches=(m:Mission,view:string)=>{
    const priority=(m.priority||"").trim().toLowerCase();
    if(view==="All") return true;
    if(view==="Open") return !isClosed(m);
    if(view==="Closed") return isClosed(m);
    if(view==="Waiting") return isWaiting(m);
    return !isClosed(m)&&priority===view.toLowerCase();
  };
  const shown=items.filter(m=>(!hideClosed||filter==="Closed"||!isClosed(m))&&matches(m,filter));
  const countFor=(view:string)=>items.filter(m=>(!hideClosed||view==="Closed"||!isClosed(m))&&matches(m,view)).length;
  return <div className="page">
    <PageHead eyebrow="MISSION CONTROL // SOURCE LINKED" title="Make the next move obvious." text="Every task can open its original email, reveal the history that produced it and generate a situation-specific action plan."/>
    <div className="mission-filter-bar">
      <div className="filters">
        {filters.map(f=><button className={filter===f?"active":""} onClick={()=>setFilter(f)} key={f}><span>{f}</span><b>{countFor(f)}</b></button>)}
      </div>
      <button className={"closed-toggle "+(hideClosed?"active":"")} onClick={()=>setHideClosed(!hideClosed)} aria-pressed={hideClosed}>
        <i>{hideClosed?"×":"✓"}</i>
        <span>{hideClosed?"Closed tasks hidden":"Closed tasks visible"}</span>
      </button>
    </div>
    <div className="mission-list">
      {shown.map(m=>{
        const isDone=isClosed(m);
        return <article className={"list-card panel "+(isDone?"is-done":"")} key={m.id}>
          <button className="check" onClick={()=>complete(m.id)}>{isDone?<Check/>:null}</button>
          <div>
            <span className={"tag "+m.priority.toLowerCase()}>{m.priority} // {m.category}</span>
            <h3>{m.title}</h3>
            <p>{m.next}</p>
            <footer>
              <span><Clock3/> Due {m.due}</span>
              <span><ShieldCheck/> {m.status}</span>
              <button onClick={()=>setSelected(m)}><History/> {m.timelineEvents||timeline.filter(e=>e.taskId===m.id).length} events</button>
              {m.sourceUrl&&<a href={gmailUrl(m.sourceUrl)} target="_blank" rel="noreferrer"><ExternalLink/> Open source</a>}
              <span>{m.id}</span>
            </footer>
          </div>
          <button className="open-record" onClick={()=>setSelected(m)}><ChevronRight/></button>
        </article>
      })}
    </div>
    {!shown.length&&<div className="empty-missions panel"><ListTodo/><h3>No tasks match this view.</h3><p>Try another filter or change the closed-task visibility.</p></div>}
    {selected&&<MissionDetail mission={selected} all={items} history={timeline.filter(e=>e.taskId===selected.id)} workLog={workLog.filter(e=>e.taskId===selected.id)} onClose={()=>setSelected(undefined)} complete={complete} saveProgress={saveProgress} done={isClosed(selected)} openUpdates={openUpdates}/>}
  </div>
}

function situationPlan(m:Mission){const plans:Record<string,{call:string;why:string;steps:string[];gap:string}>={
 "CC-003":{call:"Do not promise a payment amount on the first call.",why:"The report shows Lendable at £0 current balance but a £2,551 default balance, while collection activity refers to Perch/ACI. Ownership and the enforceable current balance need confirming first.",steps:["Ask ACI to confirm who owns the account and send a full statement in writing.","Explain the employment transition and ask for a temporary hold while you complete an income-and-expenditure budget.","After essentials, use the debt lab to calculate an affordable pro-rata monthly offer or a conditional lump-sum offer.","Do not pay a partial settlement until written terms say the remainder will not be pursued and explain the credit-file treatment."],gap:"Missing: verified current owner, current settlement balance, interest/charges status and monthly disposable income."},
 "CC-008":{call:"Build the evidence pack before negotiating the disputed figure.",why:"The hearing and July-rent tasks share payment evidence, housing stability and legal consequences.",steps:["Confirm court venue and case details from the original notice.","Create a dated rent-payment ledger with bank evidence.","Separate admitted arrears from disputed amounts.","Send the pack to the adviser and record their recommended hearing position."],gap:"Missing: verified arrears figure, venue confirmation and adviser response."},
 "CC-009":{call:"Reconcile first; respond with evidence rather than memory.",why:"This task directly affects the possession-hearing preparation and should share the same payment ledger.",steps:["Open the original Folio email.","Match each claimed period against statement payments.","Mark agreed, disputed and missing amounts.","Send one concise evidence-backed response and add it to both task timelines."],gap:"Missing: landlord rent schedule and matched payment ledger."},
 "CC-002":{call:"Treat the deadline as a decision gate, not an admin reminder.",why:"The settlement drives runway, debt options, career transition and tax uncertainty.",steps:["Confirm solicitor advice and outstanding wording.","Record the stated gross components separately from the estimated net.","Do not allocate funds until signed and cleared.","When cleared, rerun every finance scenario using the final payslip."],gap:"Missing: final signed wording, adviser certificate, payment date and actual net."},
 "CC-012":{call:"Verify each alert separately today.",why:"Multiple providers changed close together; one recognised migration does not prove every alert was expected.",steps:["Open each original alert from the event history.","Confirm device, location and timestamp.","Change passwords and revoke sessions for anything unrecognised.","Record each provider as verified or escalated."],gap:"Missing: per-alert verification result."}
 };return plans[m.id]||{call:m.next,why:`This is currently ${m.priority.toLowerCase()} priority and ${m.status.toLowerCase()}. The recommendation is based on its recorded context and latest event.`,steps:[m.next,`Open the latest source and confirm the current position with ${m.conversation||m.waiting}.`,`Record the outcome as a new timeline event rather than overwriting history.`],gap:`Missing: the outcome of the next contact and any new evidence.`}}

function MissionDetail({mission,all,history,workLog,onClose,complete,saveProgress,done,openUpdates}:{mission:Mission;all:Mission[];history:TimelineEntry[];workLog:TaskWorkEntry[];onClose:()=>void;complete:(id:string)=>void;saveProgress:(mission:Mission,planSteps:string[],checked:string[],workNote:string,nextWorkSession:string)=>void;done:boolean;openUpdates:()=>void}){const plan=situationPlan(mission);const syncedSteps=plan.steps.map((text,index)=>workLog.some(e=>(e.stepKey===`step-${index+1}`||e.stepDescription===text)&&e.completed.toLowerCase()==="yes")?String(index):"").filter(Boolean);const latestWork=[...workLog].reverse().find(e=>e.workingNote||e.nextWorkSession);const [steps,setSteps]=useStored<string[]>(`tolu-plan-${mission.id}`,syncedSteps);const [workNote,setWorkNote]=useStored(`tolu-plan-note-${mission.id}`,latestWork?.workingNote||mission.latestAppNote||"");const [session,setSession]=useStored(`tolu-plan-session-${mission.id}`,inputDateTime(latestWork?.nextWorkSession||mission.nextWorkSession));const [dirty,setDirty]=useState(false);useEffect(()=>{if(!mission.lastAppEventId)return;setSteps(current=>[...new Set([...current,...syncedSteps])]);if(!workNote&&mission.latestAppNote)setWorkNote(mission.latestAppNote);if(!session&&mission.nextWorkSession)setSession(inputDateTime(mission.nextWorkSession))},[mission.lastAppEventId]);const toggleStep=(i:number)=>{setSteps(s=>s.includes(String(i))?s.filter(x=>x!==String(i)):[...s,String(i)]);setDirty(true)};const related=all.filter(m=>m.id!==mission.id&&(m.category===mission.category||(mission.id==="CC-003"&&["CC-002","CC-006"].includes(m.id))||(mission.id==="CC-002"&&["CC-003","CC-008"].includes(m.id)))).slice(0,4);const save=()=>{saveProgress(mission,plan.steps,steps,workNote,session);setDirty(false)};return <div className="modal record-modal"><section className="record-card panel"><button className="close" onClick={onClose}><X/></button><div className="record-head"><span className={`tag ${mission.priority.toLowerCase()}`}>{mission.priority} // {mission.id}</span><h2>{mission.title}</h2><p>{mission.context||mission.notes}</p><div className="record-actions">{mission.sourceUrl&&<a className="primary" href={gmailUrl(mission.sourceUrl)} target="_blank" rel="noreferrer">Open latest source <ExternalLink/></a>}<button className="complete-btn" onClick={openUpdates}>Review all source updates <Database/></button><button className="complete-btn" onClick={()=>complete(mission.id)}><Check/> {done?"Reopen task + queue update":"Complete task + queue update"}</button></div></div><div className="record-facts"><div><span>STATUS</span><strong>{mission.status}</strong></div><div><span>DUE</span><strong>{mission.due}</strong></div><div><span>WAITING ON</span><strong>{mission.waiting}</strong></div><div><span>CONVERSATION</span><strong>{mission.conversation||"Not recorded"}</strong></div></div><section className="decision-engine"><div className="decision-core"><Sparkles/><span>DECISION ENGINE</span></div><div><span className="eyebrow">RECOMMENDED CALL</span><h2>{plan.call}</h2><p>{plan.why}</p><ol>{plan.steps.map(s=><li key={s}>{s}</li>)}</ol><small>{plan.gap}</small></div></section><section className="mission-planner"><div className="planner-title"><div><span className="eyebrow">EXECUTION ROOM // PLAN THIS TASK</span><h2>Turn advice into booked actions.</h2></div><strong>{steps.length}/{plan.steps.length}</strong></div><div className="execution-steps">{plan.steps.map((s,i)=><button className={steps.includes(String(i))?"done":""} onClick={()=>toggleStep(i)} key={s}><i>{steps.includes(String(i))?<Check/>:i+1}</i><span>{s}</span></button>)}</div><div className="planner-inputs"><label><span>NEXT WORK SESSION</span><input type="datetime-local" value={session} onChange={e=>{setSession(e.target.value);setDirty(true)}}/></label><label><span>WORKING NOTES / SCRIPT</span><textarea value={workNote} onChange={e=>{setWorkNote(e.target.value);setDirty(true)}} placeholder="Draft the call opening, questions, evidence to collect, or the exact first move…"/></label></div><div className="planner-save-row"><div><b>{dirty?"UNSAVED APP CHANGES":mission.lastAppUpdate?`MASTER SAVED // ${mission.lastAppUpdate}`:"LOCAL PLAN READY"}</b><span>{mission.planProgress||`${steps.length}/${plan.steps.length} steps`}{mission.lastAppEventId?` // ${mission.lastAppEventId}`:""}</span></div><button className="primary" onClick={save} disabled={!dirty&&!workNote&&!session&&!steps.length}><Database/> Save progress to master</button></div><div className="readiness"><i style={{width:`${Math.round(steps.length/plan.steps.length*100)}%`}}/><span>{Math.round(steps.length/plan.steps.length*100)}% EXECUTION READY</span></div></section>{workLog.length>0&&<section className="work-log-preview"><span className="eyebrow">TASK WORK LOG // {workLog.length} DURABLE ENTR{workLog.length===1?"Y":"IES"}</span>{workLog.slice(-3).reverse().map(e=><article key={e.entryId}><b>{e.entryType}</b><span>{e.loggedAt}</span><p>{e.workingNote||e.outcome||e.stepDescription}</p></article>)}</section>}{related.length>0&&<section className="connection-field"><span className="eyebrow">CONNECTED SITUATIONS // CHANGES HERE AFFECT THESE</span><div>{related.map(r=><article key={r.id}><span>{r.id}</span><strong>{r.title}</strong><small>{r.category}</small></article>)}</div></section>}<div className="history-stream"><span className="eyebrow">PERMANENT EVENT HISTORY // {history.length}</span>{history.length?history.map(e=><article key={e.id}><i/><div className="history-date"><strong>{e.date}</strong><span>{e.method} // {e.direction}</span></div><div><span className="tag">{e.type}</span><h3>{e.summary}</h3><p>{e.details}</p><small>{e.person}</small><b>NEXT: {e.next}</b>{e.sourceUrl&&<a href={gmailUrl(e.sourceUrl)} target="_blank" rel="noreferrer">Open exact source <ExternalLink/></a>}</div></article>):<p className="empty-history">No timeline events were found in this snapshot.</p>}</div></section></div>}

function SpendingPulse(){const [rule,setRule]=useStored("tolu-spend-rule",0);const rules=["One planned food shop before convenience purchases.","Use one travel wallet; treat TFL unpaid-fare charges as a system fault to resolve.","Batch family/social transfers into a named weekly allowance.","No repeated top-ups: choose a weekly Revolut amount and review it once."];return <section className="spending-pulse panel"><header><div><span className="eyebrow">FRESH IMPORT // REVOLUT MAY–JUL 2026</span><h2>Your money is leaking through friction.</h2><p>The pattern is not one spectacular purchase. It is repeated small decisions when tired, travelling, social or under pressure.</p></div><Radio/></header><div className="pulse-patterns"><article><strong>FOOD FRAGMENTATION</strong><p>Several supermarket, takeaway and snack purchases can land on the same day.</p><span>DESIGN RESPONSE // one stocked base meal + one social-food budget</span></article><article><strong>TRAVEL CHURN</strong><p>TFL, Lime, Uber and rail transactions overlap, including unpaid-fare activity.</p><span>DESIGN RESPONSE // weekly travel cap + fix payment-method failures</span></article><article><strong>TOP-UP LOOP</strong><p>Money moves into Revolut repeatedly, then leaves in small bursts.</p><span>DESIGN RESPONSE // one intentional weekly transfer</span></article><article><strong>RELATIONSHIP SPEND</strong><p>Frequent small transfers to friends/family matter even when each feels harmless.</p><span>DESIGN RESPONSE // generosity gets its own honest allowance</span></article></div><div className="pulse-rule"><Sparkles/><div><span>THIS WEEK'S BEHAVIOUR EXPERIMENT</span><strong>{rules[rule]}</strong></div><button onClick={()=>setRule((rule+1)%rules.length)}><RefreshCw/> Rotate rule</button></div><small>Pattern inference from the latest supplied statement; transfers between Tolu-owned accounts are not treated as spending. Verify categories before making decisions.</small></section>}

